    ['One to Be Feared'] = {
        id = 638,
        start_npc = 'Cid',
        start_zone = 'Sealion\'s Den',
        start_pos = 'H-8',
        description = 'The fifth verse of \'Memoria de la Stona\' has been discovered. Now, with the help of Cid, you must fly beyond the sea of clouds and face Bahamut for what may be the final time.',
        reward = 'Ducal Guard\'s Ring',
        fame = nil,
