    ['The Enduring Tumult of War'] = {
        id = 448,
        start_npc = 'Port Bastok',
        start_zone = 'Tavnazian Safehold',
        start_pos = 'K-10',
        description = 'The airship piloted by Louverance did not arrive in San d\'Oria, but Port Bastok. How much longer will Nag\'molada wait for your arrival at the northwestern tower of Pso\'Xja?',
        reward = 'Access to Promyvion - Vahzl',
        fame = nil,
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = {'Slanderous Utterings'},
        next = {'Desires of Emptiness'},
        requirements = nil,
        walkthrough = '1. (Optional): Speak to Despachiaire through the Walnut Door at (K-10) on the top floor of Tavnazian Safehold for a cutscene.\n   - He may start other quests like X Marks the Spot before triggering the cutscene: it\'s the flashback with Ulmia.\n   - (Optional): Speak to Parelbriaux by the Walnut Door at (K-7), Prishe\'s room, on the top floor of Tavnazian Safehold for a cutscene.\n   - (Optional): Speak to Odeya at (J-10) near a water pump on the top floor of Tavnazian Safehold for a cutscene. This is down the ramp from Despachiaire\'s Room.\n   - The two optional steps above provide some context for this mission, but they are ultimately lead ins for the X Marks the Spot quest, and are not necessary to move 5-1 forward.\n2. (Optional): Look for your companions at the aforementioned meeting place.\n3. (Optional): Speak to Chasalvige in Northern San d\'Oria (L-6, Cathedral Manuscript Room) for a cutscene.\n4. (Optional): Head to Port San d\'Oria and speak to Anoki (H-6, Air Travel Agency) for a cutscene.\n5. (Optional): Speak to Anoki a second time for your hint on where to go next.\n6. Zone into Port Bastok for a cutscene.\n7. Speak with Cid in the Metalworks for a cutscene.\n8. Travel to the Nue Tower at (F-7) in Beaucedine Glacier, and enter the uncapped area of Pso\'Xja for a small cutscene. (Home Point will not work.)\n9. Move ahead until you reach the Stone Door at (H-8). Checking this door will spawn a Golem named Nunyunuwi.\n   - This is the 1st of 2 stone doors that leads to Promyvion - Vahzl.\n   - This NM has very low HP (about 3,800) but incredibly high Regen (about 100HP/tick). Unload all you have on it and it should fall easily.\n10. Check the stone door again once Nunyunuwi is defeated to continue on.\n11. In the next room, take the elevator down to the bottom (there are no Diremites at the bottom of this elevator ride).\n12. Follow the path here until you reach another Stone Door for you to check, a cutscene will play and you will enter Promyvion - Vahzl.\n   - This is the 2nd of 2 Stone Doors mentioned here.\n13. You will get another cutscene upon entering.',
        notes = nil,
    },
